Issue seems to be a race condition in what I assume are different packages attempting to remove some temporary folder.

After many repeated attempts with similar errors, it succeeded once.

Then it was still failing but I could get it to work every time by changing the `_rmtree_unsafe()` function in `z:\.tox\fix-lint\lib\shutil.py`  to add `except FileNotFoundError` error handling:
```
# version vulnerable to race conditions
def _rmtree_unsafe(path, onerror):
    try:
        print('zzz: path exists:{}'.format(os.path.exists(path)))
        if os.path.islink(path):
            # symlinks to directories are forbidden, see bug #1669
            raise OSError("Cannot call rmtree on a symbolic link")
    except FileNotFoundError:
        return
    except OSError:
        onerror(os.path.islink, path, sys.exc_info())
        # can't continue even if onerror hook returns
        return
    names = []
    try:
        names = os.listdir(path)
    except FileNotFoundError:
        return
    except OSError:
        onerror(os.listdir, path, sys.exc_info())
    for name in names:
        fullname = os.path.join(path, name)
        try:
            mode = os.lstat(fullname).st_mode
        except OSError:
            mode = 0
        if stat.S_ISDIR(mode):
            _rmtree_unsafe(fullname, onerror)
        else:
            try:
                os.unlink(fullname)
            except FileNotFoundError:
                return
            except OSError:
                onerror(os.unlink, fullname, sys.exc_info())
    try:
        os.rmdir(path)
    except FileNotFoundError:
        return
    except OSError:
        onerror(os.rmdir, path, sys.exc_info())
```

